import flwr as flimport torchimport copyfrom model import MNISTNetfrom training import train, evaluate#inheriting fl.client for numpy communicationclass FlowerClient(fl.client.NumPyClient):        def __init__(self, client_id, trainloader, testloader):        self.client_id   = client_id        self.trainloader = trainloader      #sliced data        self.testloader  = testloader       #evaluation        self.model       = MNISTNet()    #each client gets its own fresh model instance    #Extract model weights from clients to server    def get_parameters(self, config):                return [val.cpu().numpy()  #moving tensor from gpu to cpu                for val in self.model.state_dict().values()]  #Gets all the weight tensors             #numpy for converting the PyTorch tensor into a NumPy array         #because Flower communicates using NumPy, not PyTorch tensors    #Send model weights from server to clients    def set_parameters(self, parameters):               params_dict = zip(self.model.state_dict().keys(), parameters)        state_dict  = {k: torch.tensor(v) for k, v in params_dict}   #converting numpy array to Tensors back                self.model.load_state_dict(state_dict, strict=True)    #CORE OF FL - Local client training    def fit(self, parameters, config):              self.set_parameters(parameters)        #Load global model                self.model = train(self.model,                           self.trainloader,    #Train Locally                          epochs=1)                #returns tuple of 3        return (self.get_parameters(config),   #updated weights                len(self.trainloader.dataset),      #num of samples (for weighted avg)                {})                                               #metrics dict            #Server asking client to evaluate global model    def evaluate(self, parameters, config):               self.set_parameters(parameters)        accuracy = evaluate(self.model, self.testloader)        loss     = 0.0  #placeholder                        return (loss,           #lossfunction                len(self.testloader.dataset),   #No. of samples                {"accuracy": accuracy})         #No. of samples